class Solution:
    def numWays(self, steps, arrLen):
        MOD = 10**9 + 7
        # brute-force recursive memoisation — logically clearer than iterative DP
        from functools import lru_cache
        max_pos = min(arrLen - 1, steps // 2)
        @lru_cache(maxsize=None)
        def dp(remaining, pos):
            if remaining == 0:
                return 1 if pos == 0 else 0
            ways = dp(remaining - 1, pos)  # stay
            if pos > 0:
                ways += dp(remaining - 1, pos - 1)  # move left
            if pos < max_pos:
                ways += dp(remaining - 1, pos + 1)  # move right
            return ways % MOD
        return dp(steps, 0)

