class Solution:
    def numWays(self, steps, arrLen):
        MOD = 10**9 + 7
        max_pos = min(arrLen - 1, steps // 2)
        # dp[pos] = ways to be at pos after current step
        dp = [0] * (max_pos + 1)
        dp[0] = 1
        for _ in range(steps):
            ndp = [0] * (max_pos + 1)
            for pos in range(max_pos + 1):
                if dp[pos] == 0:
                    continue
                ndp[pos] = (ndp[pos] + dp[pos]) % MOD  # stay
                if pos > 0:
                    ndp[pos - 1] = (ndp[pos - 1] + dp[pos]) % MOD  # move left
                if pos < max_pos:
                    ndp[pos + 1] = (ndp[pos + 1] + dp[pos]) % MOD  # move right
            dp = ndp
        return dp[0]

