var numWays = function(steps, arrLen) {
    const MOD = 1000000007n;
    const maxPos = Math.min(arrLen - 1, Math.floor(steps / 2));
    let dp = new Array(maxPos + 1).fill(0n);
    dp[0] = 1n;
    for (let s = 0; s < steps; s++) {
        const ndp = new Array(maxPos + 1).fill(0n);
        for (let pos = 0; pos <= maxPos; pos++) {
            if (dp[pos] === 0n) continue;
            ndp[pos] = (ndp[pos] + dp[pos]) % MOD;
            if (pos > 0) ndp[pos - 1] = (ndp[pos - 1] + dp[pos]) % MOD;
            if (pos < maxPos) ndp[pos + 1] = (ndp[pos + 1] + dp[pos]) % MOD;
        }
        dp = ndp;
    }
    return Number(dp[0]);
};
